PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?heritage WHERE {
  wd:Q117494853 wdt:P1435 ?heritage .
}

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>

SELECT ?longitude WHERE {
  wd:Q117494853 wdt:P625 ?coord .
  BIND(xsd:float(STRBEFORE(STRAFTER(STR(?coord), "("), " ")) AS ?longitude)
}

